<div class='grid'><div><label>Requester user ID</label><input name='user_id' value='{{ old('user_id', $ticket->user_id ?? auth()->id()) }}'></div><div><label>Agent user ID</label><input name='agent_id' value='{{ old('agent_id', $ticket->agent_id ?? '') }}'></div><div><label>Title</label><input name='title' value='{{ old('title', $ticket->title ?? '') }}'></div><div><label>Type</label><select name='feedback_type'>@foreach(['complaint','feedback','survey_response'] as $type)<option value='{{ $type }}' @selected(old('feedback_type', $ticket->feedback_type ?? 'feedback')===$type)>{{ $type }}</option>@endforeach</select></div><div><label>Status</label><select name='status'>@foreach(['open','in_progress','pending','resolved','closed'] as $status)<option value='{{ $status }}' @selected(old('status', $ticket->status ?? 'open')===$status)>{{ $status }}</option>@endforeach</select></div><div><label>Priority</label><select name='priority'>@foreach(['low','medium','high','critical'] as $priority)<option value='{{ $priority }}' @selected(old('priority', $ticket->priority ?? 'medium')===$priority)>{{ $priority }}</option>@endforeach</select></div><div><label>Channel</label><select name='channel_id'><option value=''>None</option>@foreach(($channels ?? collect()) as $channel)<option value='{{ $channel->id }}' @selected(old('channel_id', $ticket->channel_id ?? '')==$channel->id)>{{ $channel->name }}</option>@endforeach</select></div><div><label>Group</label><select name='group_id'><option value=''>None</option>@foreach(($groups ?? collect()) as $group)<option value='{{ $group->id }}' @selected(old('group_id', $ticket->group_id ?? '')==$group->id)>{{ $group->name }}</option>@endforeach</select></div><div><label>Ticket type</label><select name='type_id'><option value=''>None</option>@foreach(($types ?? collect()) as $type)<option value='{{ $type->id }}' @selected(old('type_id', $ticket->type_id ?? '')==$type->id)>{{ $type->name }}</option>@endforeach</select></div><div><label>NPS score</label><input name='nps_score' value='{{ old('nps_score', $ticket->nps_score ?? '') }}'></div><div><label>CSAT score</label><input name='csat_score' value='{{ old('csat_score', $ticket->csat_score ?? '') }}'></div></div><label>Description</label><textarea name='description' rows='7'>{{ old('description', $ticket->description ?? '') }}</textarea><button class='btn'>Save</button>